import React from 'react';
import { NavLink, Route, Routes } from 'react-router-dom';
import RequireRole from './auth/RequireRole';
import { useRole } from './auth/RoleContext';
import ClientDashboardPage from './pages/ClientDashboardPage';
import FindTrainerPage from './pages/FindTrainerPage';
import SessionsPage from './pages/SessionsPage';
import SignupPage from './pages/SignupPage';
import TrainerDashboardPage from './pages/TrainerDashboardPage';
import './styles.css';
import { Flex, Heading, Text } from '@radix-ui/themes';

const App = () => {
  const { role } = useRole();

  return (
    <main className="app-shell">
      <header className="app-topbar">
        <Flex align="center" className="app-brand">
          <Heading>FitMarket</Heading>
        </Flex>
        <nav className="app-nav">
          {role === 'client' ? (
            <>
              <NavLink to="/client" className={({ isActive }) => (isActive ? 'active-link' : '')}>
                <Text>Dashboard</Text>
              </NavLink>
              <NavLink to="/client/find-trainer" className={({ isActive }) => (isActive ? 'active-link' : '')}>
                <Text>Find Trainer</Text>
              </NavLink>
              <NavLink to="/client/sessions" className={({ isActive }) => (isActive ? 'active-link' : '')}>
                <Text>My Sessions</Text>
              </NavLink>
            </>
          ) : null}
          {role === 'trainer' ? (
            <>
              <NavLink to="/trainer" className={({ isActive }) => (isActive ? 'active-link' : '')}>
                <Text>Dashboard</Text>
              </NavLink>
              <NavLink to="/trainer/schedule" className={({ isActive }) => (isActive ? 'active-link' : '')}>
                <Text>Schedule</Text>
              </NavLink>
            </>
          ) : null}
        </nav>
        <div className="app-topbar-spacer" aria-hidden="true" />
      </header>

      <Routes>
        <Route path="/" element={<SignupPage />} />
        <Route
          path="/client"
          element={
            <RequireRole allowedRole="client">
              <ClientDashboardPage />
            </RequireRole>
          }
        />
        <Route
          path="/client/find-trainer"
          element={
            <RequireRole allowedRole="client">
              <FindTrainerPage />
            </RequireRole>
          }
        />
        <Route
          path="/client/sessions"
          element={
            <RequireRole allowedRole="client">
              <SessionsPage />
            </RequireRole>
          }
        />
        <Route
          path="/trainer"
          element={
            <RequireRole allowedRole="trainer">
              <TrainerDashboardPage />
            </RequireRole>
          }
        />
        <Route
          path="/trainer/schedule"
          element={
            <RequireRole allowedRole="trainer">
              <SessionsPage />
            </RequireRole>
          }
        />
      </Routes>
    </main>
  );
};

export default App;
